DO
BEGIN
  DECLARE sets_exists INTEGER;
  DECLARE sections_exists INTEGER;
  DECLARE question_items_exists INTEGER;
  DECLARE question_items_index_exists INTEGER;

  SELECT COUNT(*)
    INTO sets_exists
    FROM SYS.TABLES
   WHERE SCHEMA_NAME = 'ITIL_EXAM'
     AND TABLE_NAME = 'QUESTION_SETS';

  IF :sets_exists = 0 THEN
    EXECUTE IMMEDIATE '
      CREATE TABLE "ITIL_EXAM"."QUESTION_SETS" (
        "QUESTION_SET_ID" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
        "NAME" NVARCHAR(255) NOT NULL,
        "DESCRIPTION" NVARCHAR(1000),
        "IS_ACTIVE" BOOLEAN DEFAULT FALSE NOT NULL,
        "DURATION_MINUTES" INTEGER DEFAULT 45 NOT NULL,
        "PASS_PCT" INTEGER DEFAULT 80 NOT NULL,
        "PROCTOR_ENABLED" BOOLEAN DEFAULT TRUE NOT NULL,
        "NUM_QUESTIONS" INTEGER,
        "CREATED_AT" TIMESTAMP DEFAULT CURRENT_UTCTIMESTAMP NOT NULL,
        "UPDATED_AT" TIMESTAMP DEFAULT CURRENT_UTCTIMESTAMP NOT NULL
      )
    ';
  END IF;

  SELECT COUNT(*)
    INTO sections_exists
    FROM SYS.TABLES
   WHERE SCHEMA_NAME = 'ITIL_EXAM'
     AND TABLE_NAME = 'QUESTION_SECTIONS';

  IF :sections_exists = 0 THEN
    EXECUTE IMMEDIATE '
      CREATE TABLE "ITIL_EXAM"."QUESTION_SECTIONS" (
        "SECTION_ID" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
        "QUESTION_SET_ID" BIGINT NOT NULL,
        "NAME" NVARCHAR(255) NOT NULL,
        "DESCRIPTION" NVARCHAR(1000),
        "DISPLAY_ORDER" INTEGER DEFAULT 0 NOT NULL,
        "DRAW_COUNT" INTEGER,
        "CREATED_AT" TIMESTAMP DEFAULT CURRENT_UTCTIMESTAMP NOT NULL,
        "UPDATED_AT" TIMESTAMP DEFAULT CURRENT_UTCTIMESTAMP NOT NULL,
        CONSTRAINT "FK_QSECTIONS_SET" FOREIGN KEY ("QUESTION_SET_ID")
          REFERENCES "ITIL_EXAM"."QUESTION_SETS" ("QUESTION_SET_ID")
          ON DELETE CASCADE
      )
    ';
  END IF;

  SELECT COUNT(*)
    INTO question_items_exists
    FROM SYS.TABLES
   WHERE SCHEMA_NAME = 'ITIL_EXAM'
     AND TABLE_NAME = 'QUESTION_SET_QUESTIONS';

  IF :question_items_exists = 0 THEN
    EXECUTE IMMEDIATE '
      CREATE TABLE "ITIL_EXAM"."QUESTION_SET_QUESTIONS" (
        "QUESTION_ID" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
        "QUESTION_SET_ID" BIGINT NOT NULL,
        "SECTION_ID" BIGINT,
        "QUESTION_INDEX" INTEGER NOT NULL,
        "STEM" NCLOB NOT NULL,
        "NOTE" NCLOB,
        "OPTS_JSON" NCLOB NOT NULL,
        "ANSWER_JSON" NCLOB NOT NULL,
        "MULTI" BOOLEAN DEFAULT FALSE NOT NULL,
        "CREATED_AT" TIMESTAMP DEFAULT CURRENT_UTCTIMESTAMP NOT NULL,
        "UPDATED_AT" TIMESTAMP DEFAULT CURRENT_UTCTIMESTAMP NOT NULL,
        CONSTRAINT "FK_QITEMS_SET" FOREIGN KEY ("QUESTION_SET_ID")
          REFERENCES "ITIL_EXAM"."QUESTION_SETS" ("QUESTION_SET_ID")
          ON DELETE CASCADE,
        CONSTRAINT "FK_QITEMS_SECTION" FOREIGN KEY ("SECTION_ID")
          REFERENCES "ITIL_EXAM"."QUESTION_SECTIONS" ("SECTION_ID")
          ON DELETE SET NULL
      )
    ';
  END IF;

  SELECT COUNT(*)
    INTO question_items_index_exists
    FROM SYS.INDEXES
   WHERE SCHEMA_NAME = 'ITIL_EXAM'
     AND INDEX_NAME = 'UX_QITEMS_SET_QINDEX';

  IF :question_items_index_exists = 0 THEN
    EXECUTE IMMEDIATE '
      CREATE UNIQUE INDEX "UX_QITEMS_SET_QINDEX"
        ON "ITIL_EXAM"."QUESTION_SET_QUESTIONS" ("QUESTION_SET_ID", "QUESTION_INDEX")
    ';
  END IF;
END;

DO
BEGIN
  DECLARE access_codes_has_set INTEGER;

  SELECT COUNT(*)
    INTO access_codes_has_set
    FROM SYS.TABLE_COLUMNS
   WHERE SCHEMA_NAME = 'ITIL_EXAM'
     AND TABLE_NAME = 'ACCESS_CODES'
     AND COLUMN_NAME = 'QUESTION_SET_ID';

  IF :access_codes_has_set = 0 THEN
    EXECUTE IMMEDIATE '
      ALTER TABLE "ITIL_EXAM"."ACCESS_CODES"
      ADD ("QUESTION_SET_ID" BIGINT)
    ';
    EXECUTE IMMEDIATE '
      ALTER TABLE "ITIL_EXAM"."ACCESS_CODES"
      ADD CONSTRAINT "FK_ACCESS_CODES_QSET"
      FOREIGN KEY ("QUESTION_SET_ID")
      REFERENCES "ITIL_EXAM"."QUESTION_SETS" ("QUESTION_SET_ID")
      ON DELETE SET NULL
    ';
  END IF;
END;

DO
BEGIN
  DECLARE legacy_exam_questions_exists INTEGER;

  EXECUTE IMMEDIATE '
    INSERT INTO "ITIL_EXAM"."QUESTION_SETS"
      ("NAME", "DESCRIPTION", "IS_ACTIVE", "DURATION_MINUTES", "PASS_PCT", "PROCTOR_ENABLED", "NUM_QUESTIONS", "CREATED_AT", "UPDATED_AT")
    SELECT
      ''ITIL 4 Foundation'',
      ''Migrated default exam set'',
      TRUE,
      45,
      80,
      TRUE,
      NULL,
      CURRENT_UTCTIMESTAMP,
      CURRENT_UTCTIMESTAMP
    FROM DUMMY
    WHERE NOT EXISTS (
      SELECT 1
        FROM "ITIL_EXAM"."QUESTION_SETS"
    )
  ';

  EXECUTE IMMEDIATE '
    UPDATE "ITIL_EXAM"."QUESTION_SETS"
       SET "IS_ACTIVE" = CASE
         WHEN "QUESTION_SET_ID" = (SELECT MIN("QUESTION_SET_ID") FROM "ITIL_EXAM"."QUESTION_SETS")
         THEN TRUE ELSE FALSE END,
           "UPDATED_AT" = CURRENT_UTCTIMESTAMP
     WHERE NOT EXISTS (
       SELECT 1 FROM "ITIL_EXAM"."QUESTION_SETS" WHERE "IS_ACTIVE" = TRUE
     )
  ';

  SELECT COUNT(*)
    INTO legacy_exam_questions_exists
    FROM SYS.TABLES
   WHERE SCHEMA_NAME = 'ITIL_EXAM'
     AND TABLE_NAME = 'EXAM_QUESTIONS';

  IF :legacy_exam_questions_exists > 0 THEN
    EXECUTE IMMEDIATE '
      INSERT INTO "ITIL_EXAM"."QUESTION_SET_QUESTIONS"
        ("QUESTION_SET_ID", "QUESTION_INDEX", "STEM", "NOTE", "OPTS_JSON", "ANSWER_JSON", "MULTI", "CREATED_AT", "UPDATED_AT")
      SELECT
        (SELECT MIN("QUESTION_SET_ID") FROM "ITIL_EXAM"."QUESTION_SETS" WHERE "IS_ACTIVE" = TRUE),
        q."QUESTION_INDEX",
        q."STEM",
        q."NOTE",
        q."OPTS_JSON",
        q."ANSWER_JSON",
        q."MULTI",
        COALESCE(q."UPDATED_AT", CURRENT_UTCTIMESTAMP),
        COALESCE(q."UPDATED_AT", CURRENT_UTCTIMESTAMP)
      FROM "ITIL_EXAM"."EXAM_QUESTIONS" q
      WHERE NOT EXISTS (
        SELECT 1 FROM "ITIL_EXAM"."QUESTION_SET_QUESTIONS"
      )
      ORDER BY q."QUESTION_INDEX"
    ';
  END IF;
END;
